class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        // Make it perfectly fit the container bounds
        this.canvas.style.width = '100%';
        this.canvas.style.height = '100%';
        // Give it rounded corners and a modern dark aesthetic 
        this.canvas.style.borderRadius = '12px';
        this.container.appendChild(this.canvas);
        this.ctx = this.canvas.getContext('2d');

        // Handle Resizing Dynamically
        window.addEventListener('resize', () => this.resizeCanvas(initialInputs));
        this.resizeCanvas(initialInputs);
    }

    resizeCanvas(inputs) {
        const rect = this.container.getBoundingClientRect();
        this.canvas.width = rect.width;
        this.canvas.height = rect.height;
        this.update(inputs);
    }

    update(inputs) {
        const w = this.canvas.width;
        const h = this.canvas.height;
        const cx = w / 2;
        const cy = h / 2 + 50;

        // Clear
        this.ctx.clearRect(0, 0, w, h);

        // Variables
        const angleRad = inputs.angle * Math.PI / 180;
        const mass = inputs.mass;
        const g = inputs.gravity;

        // Visual scaling factors
        const rampLength = 400;
        const blockSide = 60 + (mass * 0.5);

        this.ctx.save();
        this.ctx.translate(cx, cy);

        // 1. Draw Ramp (Fixed base, rotating incline)
        this.ctx.beginPath();
        this.ctx.moveTo(-rampLength/2, Math.tan(angleRad) * (rampLength/2)); // Left high point
        this.ctx.lineTo(rampLength/2, Math.tan(angleRad) * (-rampLength/2)); // Right low point
        this.ctx.lineTo(rampLength/2, Math.tan(angleRad) * (rampLength/2)); // Right bottom corner
        this.ctx.closePath();
        this.ctx.fillStyle = 'rgba(100, 116, 139, 0.2)';
        this.ctx.fill();
        this.ctx.strokeStyle = '#94a3b8';
        this.ctx.lineWidth = 4;
        this.ctx.stroke();

        // 2. Setup Rotated Coordinate System for Block
        this.ctx.rotate(-angleRad);

        // Draw Block
        this.ctx.fillStyle = '#3b82f6'; // Tailwind Blue 500
        this.ctx.fillRect(-blockSide/2, -blockSide, blockSide, blockSide);
        this.ctx.strokeStyle = '#60a5fa';
        this.ctx.strokeRect(-blockSide/2, -blockSide, blockSide, blockSide);

        // Coordinate Center (Center of mass of block)
        const cmY = -blockSide/2;

        // Force Vector Helper
        const drawVector = (dx, dy, color, label) => {
            // Scale forces for visual purposes (Logarithmic-ish to prevent huge arrows)
            const mag = Math.sqrt(dx*dx + dy*dy);
            if (mag < 0.1) return;
            const scale = 20 + Math.log10(mag + 1) * 30;
            const ux = dx/mag; 
            const uy = dy/mag;
            const endX = ux * scale;
            const endY = cmY + uy * scale;

            this.ctx.beginPath();
            this.ctx.moveTo(0, cmY);
            this.ctx.lineTo(endX, endY);
            this.ctx.strokeStyle = color;
            this.ctx.lineWidth = 3;
            this.ctx.stroke();

            // Arrowhead
            const headLen = 10;
            const aAngle = Math.atan2(uy, ux);
            this.ctx.beginPath();
            this.ctx.moveTo(endX, endY);
            this.ctx.lineTo(endX - headLen * Math.cos(aAngle - Math.PI/6), endY - headLen * Math.sin(aAngle - Math.PI/6));
            this.ctx.moveTo(endX, endY);
            this.ctx.lineTo(endX - headLen * Math.cos(aAngle + Math.PI/6), endY - headLen * Math.sin(aAngle + Math.PI/6));
            this.ctx.stroke();

            // Label
            this.ctx.fillStyle = color;
            this.ctx.font = '14px Inter';
            this.ctx.fillText(label, endX + 10, endY + 10);
        };

        // Calculate physical forces in the rotated frame
        // Gravity straight down visually means rotating it BACK by +angleRad
        const fg = mass * g;
        drawVector(Math.sin(angleRad) * fg, Math.cos(angleRad) * fg, '#f59e0b', 'mg'); // Gravity

        const fn = fg * Math.cos(angleRad);
        drawVector(0, -fn, '#10b981', 'N'); // Normal (Straight up in local frame)

        const fk = 0.2 * fn;
        if (angleRad > 0) {
            drawVector(-fk, 0, '#ef4444', 'f_k'); // Friction (opposing motion up incline)
        }

        this.ctx.restore();

        // Text Overlay Data
        this.ctx.fillStyle = 'rgba(15, 23, 42, 0.8)';
        this.ctx.fillRect(10, 10, 220, 100);
        this.ctx.strokeStyle = '#334155';
        this.ctx.strokeRect(10, 10, 220, 100);

        this.ctx.fillStyle = '#f8fafc';
        this.ctx.font = 'bold 16px Inter';
        this.ctx.fillText(`System Measurements`, 25, 35);
        this.ctx.font = '14px Fira Code';
        this.ctx.fillStyle = '#94a3b8';
        this.ctx.fillText(`Weight (mg) = ${fg.toFixed(1)} N`, 25, 60);
        this.ctx.fillText(`Normal (N) = ${fn.toFixed(1)} N`, 25, 80);
        this.ctx.fillText(`Friction (fk) = ${fk.toFixed(1)} N`, 25, 100);
    }
}
